var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"으핫냐!","JPN":"うひゃっ！","ENG":"Wahh!","TWN":"啊！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"깜짝아. 천둥 치는 줄 알았네.","JPN":"びっくりした。雷かと思ったよ。","ENG":"Whoa. Thought that was thunder.","TWN":"嚇我一跳，我還以為打雷咧。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부- 오늘은 꼭두새벽부터 수련이야?","JPN":"師匠～今日は朝早くから鍛錬なの？","ENG":"Master, are we really training at the crack of dawn today?","TWN":"師父，今天一大早就開始修行喔？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"앤디?","JPN":"アンディー？","ENG":"Andy?","TWN":"安狄？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"빈틈.","JPN":"隙あり。","ENG":"Gotcha.","TWN":"有破綻。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"컥…!","JPN":"がはっ……！","ENG":"Kuh…!","TWN":"唔…！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"꺄아아! 사부가 죽었어!","JPN":"きゃああ！　師匠が死んじゃった！！","ENG":"Kyaah! Master's dead!","TWN":"啊啊啊！師父死了！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"살아있으니 호들갑 떨 거 없다.","JPN":"生きている。騒ぐな。","ENG":"He's alive. Don't be so dramatic.","TWN":"他還活著，別大驚小怪的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"주변의 소리에 집중력이 흐트러지다니. 아직 멀었어.","JPN":"周囲の音に気を取られるとは、まだまだだな。","ENG":"Losing focus from a little noise. You've got a long way to go.","TWN":"竟然被周圍的聲音分散注意力，看來你還差得遠呢。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…면목 없군. 장소를 바꿔서 다시 시작하지.","JPN":"……面目ない。場所を変えてやり直そう。","ENG":"…My apologies. Let's move somewhere else and start over.","TWN":"…抱歉。換個地方再開始吧。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"잠깐…! 사부! 피가 나는데 계속 싸우려고?","JPN":"待って……！　師匠！　血が出てるのにそのまま続けるの？","ENG":"Hold on…! Master! You're bleeding but still planning to keep fighting?","TWN":"等等…！師父！都流血了還要繼續嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"걱정 말게. 나무는 상처 입을수록 더욱 단단해지는 법이니.","JPN":"心配いらん。木は傷が増えるほど丈夫になるものゆえ。","ENG":"Don't worry. Trees grow stronger the more they're wounded.","TWN":"別擔心。樹木受傷後，反而會變得更加堅韌。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"오, 방금 대사는… 좀 멋있네.","JPN":"お、今の台詞……ちょっとかっこいいかも。","ENG":"Okay, that was… kind of cool.","TWN":"喔，這句話…有點帥喔。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"근데 사부는 나무아니거든? 사람이거든?! 상처 덧나기라도 하면 어쩌려고!","JPN":"でも師匠は木じゃなくて人間だからね！？　傷が悪化したら大変だよ！","ENG":"But Master, you're not a tree. You're a human! What if the wound gets worse?!","TWN":"但師父又不是樹木！你是人欸？！萬一傷口感染怎麼辦！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"버릇이란 건 참으로 무서운 걸세.","JPN":"癖とは怖いものだ。","ENG":"Habits are terrifying things.","TWN":"習慣是件很可怕的東西。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"상처 입은 정도로 포기한다면, 그 포기 또한 몸에 익어버리고 말겠지.","JPN":"傷を負ったくらいで諦めては、いずれそれが当たり前になってしまう。","ENG":"If you get used to giving up from a scratch, then giving up becomes a habit too.","TWN":"如果因為受傷就放棄，那放棄也會變成一種習慣。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그… 그런가? 듣고 보니 설득되는 것 같기도 하구.","JPN":"そ……そうかな？　言われてみるとそんな気も……","ENG":"R-really? When you put it that way, I guess that makes sense.","TWN":"這…是這樣嗎？聽你這麼一說，好像也有點道理。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"점심 전까진 돌아오도록 하지.","JPN":"昼食前には戻って来よう。","ENG":"I'll be back before lunch.","TWN":"午飯前我會回來的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"하아, 바보 약골 사부. 자기가 무슨 명언제조기인 줄 안다니까.","JPN":"はあ、バカヒョロ師匠。自分のこと名言メーカーか何かだと勘違いしてるんじゃないの？","ENG":"*Sigh* Stupid, weak Master. Thinks he's some kind of quote machine.","TWN":"唉，笨蛋弱雞師父。還以為自己是什麼名言製造機嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"맷집이랑 체력은 나랑 별 차이도 안 나면서 요즘 왜 저렇게 무리하는 거람?","JPN":"打たれ強さも体力も私と大して変わらないくせに……無茶しすぎなんだよ、ほんと。","ENG":"He's barely tougher than me, so why's he pushing himself so hard lately?","TWN":"明明體力和我沒差多少，最近怎麼這麼拼命？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"연화 언니를 이긴다고 해서 정말 과거가 바뀌는지도 아직 모르는 거잖아.","JPN":"レンカさんに勝っても本当に過去が変わるかどうかなんて、まだ分からないのに。","ENG":"Even if he beats Yeonhwa, we don't even know if that'll actually change the past.","TWN":"就算打贏蓮華姊姊，也不知道是不是真的就能改變過去。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"피 흘린 사람한텐 고기 요리라도 먹이는 게 좋겠지?","JPN":"血流した人にはやっぱり肉料理がいいよね。","ENG":"Someone who bled should probably eat meat, right?","TWN":"流血的人，要吃肉補血吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}}]`);export{e as default};